}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and language." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and civilizations." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, loops, methods, and object-oriented programming basics.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a Ph.D. from MIT and has published extensively on programming pedagogy.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", InstructorName = "Dr. James Okafor", InstructorBio = "Dr. Okafor is an expert in algorithm optimization with research published in top-tier conferences. He previously worked at a major tech company on distributed systems.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Code = "CS 310", Title = "Database Systems", Description = "Design and implementation of relational databases. Covers SQL, normalization, indexing, transaction management, and introduction to NoSQL systems.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Prof. Maria Lopez", InstructorBio = "Prof. Lopez spent a decade in industry building large-scale data platforms before joining academia. Her courses emphasize practical, hands-on database skills.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Code = "MATH 151", Title = "Calculus I", Description = "Introduction to differential calculus. Topics include limits, continuity, derivatives, and applications of differentiation.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning mathematics educator known for making abstract concepts accessible. He has authored two popular calculus textbooks.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Code = "MATH 250", Title = "Linear Algebra", Description = "Study of vector spaces, matrices, linear transformations, eigenvalues, and applications in science and engineering.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emily Novak", InstructorBio = "Dr. Novak's research focuses on numerical linear algebra and scientific computing. She collaborates with engineering departments on applied mathematics projects.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Code = "ENG 110", Title = "Academic Writing", Description = "Develop skills in essay writing, argumentation, research methods, and critical reading. Emphasis on clear, effective communication.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Prof. David Atwood", InstructorBio = "Prof. Atwood is a published author and writing instructor with 20 years of experience helping students find their voice in academic and creative contexts.", DepartmentId = 3, DepartmentName = "English", IsFeatured = false },
            new() { Id = 7, Code = "ENG 220", Title = "World Literature", Description = "Survey of major literary works from around the globe, spanning ancient epics to modern novels. Explores themes of identity, power, and culture.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:15 PM", InstructorName = "Dr. Aisha Patel", InstructorBio = "Dr. Patel specializes in postcolonial literature and comparative literary studies. She has received multiple awards for her teaching and mentorship.", DepartmentId = 3, DepartmentName = "English", IsFeatured = true },
            new() { Id = 8, Code = "PHYS 101", Title = "General Physics I", Description = "Introduction to mechanics, thermodynamics, and waves. Includes laboratory sessions with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:00 PM", InstructorName = "Dr. Thomas Wright", InstructorBio = "Dr. Wright is an experimental physicist whose research involves particle detection. He brings real-world lab experience into the classroom.", DepartmentId = 4, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 9, Code = "PHYS 210", Title = "Modern Physics", Description = "Introduction to special relativity, quantum mechanics, atomic structure, and nuclear physics.", Credits = 3, Schedule = "Tue/Thu 3:00–4:15 PM", InstructorName = "Dr. Lisa Huang", InstructorBio = "Dr. Huang is a theoretical physicist with expertise in quantum information theory. She actively publishes research and involves undergraduates in her projects.", DepartmentId = 4, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 10, Code = "HIST 105", Title = "World History to 1500", Description = "Survey of major civilizations, empires, and cultural developments from prehistory through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is a historian specializing in ancient Mediterranean civilizations. He leads archaeological field projects and integrates primary sources into his teaching.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
            new() { Id = 11, Code = "HIST 205", Title = "Modern World History", Description = "Examines global developments from the Enlightenment to the present, including revolutions, industrialization, colonialism, and globalization.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Karen Johansson", InstructorBio = "Dr. Johansson specializes in 20th-century diplomatic history and teaches courses that connect historical patterns to current global affairs.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0;
    }
}

